    const unit = makeUnit('const awsKey = "AKIAIOSFODNN7EXAMPLE";');
    const results = await detector.detect([unit], createContext());
    const awsResult = results.find(r => r.metadata?.patternId === 'aws-access-key');
    expect(awsResult).toBeDefined();
    expect(awsResult!.confidence).toBe(0.95);
