    const unit = makeUnit('const key = `-----BEGIN RSA PRIVATE KEY-----\nMIIE...`;');
    const results = await detector.detect([unit], createContext());
    const pkResult = results.find(r => r.metadata?.patternId === 'private-key');
    expect(pkResult).toBeDefined();
    expect(pkResult!.severity).toBe('error');
